// Helper functions
func formatDate(timestamp uint32) string {
	t := time.Unix(int64(timestamp), 0)
	return t.Format("January 2, 2006")
}

func getCategoryEmoji(category *string) string {
	if category == nil {
		return "📍"
	}

	switch *category {
	case "Restaurant":
		return "🍕"
	case "Landmark":
		return "🗿"
	case "Hotel":
		return "🏨"
	case "Museum":
		return "🏛️"
	case "Park":
		return "🌸"
	default:
		return "📍"
	}
}

func getStringValue(s *string) string {
	if s == nil {
		return ""
	}
	return *s
}

